mapper.select:
SELECT id, course_id, student_id, feedback_date, dimension, score,
       comment, is_analyzed, created_at
FROM feedback WHERE id = #{id}

SELECT id, course_id, student_id, feedback_date, dimension, score,
       comment, is_analyzed, created_at
FROM feedback WHERE course_id = #{courseId}
  AND feedback_date >= #{startDate} AND feedback_date <= #{endDate}
ORDER BY feedback_date, created_at
